'use client'
import { cn } from '@cascivo/core'
import styles from './progress-indicator.module.css'

export interface ProgressStep {
  label: string
  description?: string
}

export interface ProgressIndicatorProps {
  steps: ProgressStep[]
  currentIndex: number
  vertical?: boolean
  className?: string
}

type StepStatus = 'complete' | 'current' | 'incomplete'

export function ProgressIndicator({
  steps,
  currentIndex,
  vertical = false,
  className,
}: ProgressIndicatorProps) {
  return (
    <ol
      className={cn(styles['indicator'], className)}
      data-orientation={vertical ? 'vertical' : 'horizontal'}
    >
      {steps.map((step, index) => {
        const status: StepStatus =
          index < currentIndex ? 'complete' : index === currentIndex ? 'current' : 'incomplete'
        return (
          <li
            key={index}
            className={styles['step']}
            data-status={status}
            aria-current={status === 'current' ? 'step' : undefined}
          >
            <span className={styles['marker']} aria-hidden="true">
              {status === 'complete' ? '✓' : index + 1}
            </span>
            <span className={styles['text']}>
              <span className={styles['label']}>{step.label}</span>
              {step.description && (
                <span className={styles['description']}>{step.description}</span>
              )}
            </span>
          </li>
        )
      })}
    </ol>
  )
}

@layer cascivo.component {
  .indicator {
    --_marker-size: 2rem;
    --_connector-thickness: 2px;

    display: flex;
    margin: 0;
    padding: 0;
    list-style: none;
    font-family: var(--cascivo-font-sans);
  }

  .step {
    position: relative;
    display: flex;
    flex: 1;
    flex-direction: column;
    align-items: center;
    gap: var(--cascivo-space-2);
    text-align: center;

    /* Connector leading into this step (horizontal) */
    &:not(:first-child)::before {
      content: '';
      position: absolute;
      block-size: var(--_connector-thickness);
      inset-block-start: calc(var(--_marker-size) / 2 - var(--_connector-thickness) / 2);
      inset-inline-start: calc(-50% + var(--_marker-size) / 2 + var(--cascivo-space-2));
      inset-inline-end: calc(50% + var(--_marker-size) / 2 + var(--cascivo-space-2));
      background-color: var(--cascivo-color-border);
    }

    &[data-status='complete']::before,
    &[data-status='current']::before {
      background-color: var(--cascivo-color-accent);
    }
  }

  .marker {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    inline-size: var(--_marker-size);
    block-size: var(--_marker-size);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    line-height: var(--cascivo-leading-none);
    border-radius: var(--cascivo-radius-full);
    border: var(--_connector-thickness) solid var(--cascivo-color-border);
    color: var(--cascivo-color-text-muted);
    background-color: var(--cascivo-color-surface);
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      color var(--cascivo-duration-150) var(--cascivo-ease-out);

    .step[data-status='complete'] & {
      background-color: var(--cascivo-color-accent);
      border-color: var(--cascivo-color-accent);
      color: var(--cascivo-color-text-on-accent);
    }

    .step[data-status='current'] & {
      border-color: var(--cascivo-color-accent);
      color: var(--cascivo-color-accent);
      box-shadow: 0 0 0 4px var(--cascivo-color-accent-subtle);
    }
  }

  .text {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
  }

  .label {
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    line-height: var(--cascivo-leading-snug);
    color: var(--cascivo-color-text-muted);

    .step[data-status='complete'] &,
    .step[data-status='current'] & {
      color: var(--cascivo-color-text);
    }
  }

  .description {
    font-size: var(--cascivo-text-xs);
    line-height: var(--cascivo-leading-snug);
    color: var(--cascivo-color-text-subtle);
  }

  /* Vertical orientation */
  .indicator[data-orientation='vertical'] {
    flex-direction: column;

    .step {
      flex: none;
      flex-direction: row;
      align-items: flex-start;
      gap: var(--cascivo-space-3);
      text-align: start;
      padding-block-end: var(--cascivo-space-6);

      &:last-child {
        padding-block-end: 0;
      }

      &::before {
        display: none;
      }

      /* Connector leading out of this step (vertical) */
      &:not(:last-child)::after {
        content: '';
        position: absolute;
        inline-size: var(--_connector-thickness);
        inset-inline-start: calc(var(--_marker-size) / 2 - var(--_connector-thickness) / 2);
        inset-block-start: calc(var(--_marker-size) + var(--cascivo-space-2));
        inset-block-end: var(--cascivo-space-2);
        background-color: var(--cascivo-color-border);
      }

      &[data-status='complete']::after {
        background-color: var(--cascivo-color-accent);
      }
    }

    .text {
      padding-block-start: calc(
        (var(--_marker-size) - var(--cascivo-text-sm) * var(--cascivo-leading-snug)) / 2
      );
    }
  }
}
